function sliderConstruction() {
    var swiper = new Swiper('.construction .mySwiper', {
        slidesPerView: 1,
        spaceBetween: 15,
        effect: "fade",
        navigation: {
            nextEl: ".construction .swiper-button-next",
            prevEl: ".construction .swiper-button-prev",
        },
    })
}

function sliderExcursion() {
    var swiper = new Swiper('.excursion .mySwiper', {
        slidesPerView: 1,
        spaceBetween: 15,
        effect: "fade",
        navigation: {
            nextEl: ".excursion .swiper-button-next",
            prevEl: ".excursion .swiper-button-prev",
        },
        pagination: {
            el: ".excursion .swiper-pagination",
            clickable: true
        },
    })
}

