// Animation
gsap.registerPlugin(ScrollTrigger);

// Map
if (window.innerWidth >= 993) {
    const mapSection = document.querySelector('.map');
    const img1 = mapSection.querySelector('.map__img');
    const img2 = mapSection.querySelector('.map__img2 img');
    const img1DisappearLength = 600;
    const img2AppearLength = 300;
    const pinExtra = 200;
    function animateMap() {
        ScrollTrigger.matchMedia({
            "(min-width: 320px)": function () {
                const img1Bottom = img1.getBoundingClientRect().bottom + window.pageYOffset;
                const mapTop = mapSection.getBoundingClientRect().top + window.pageYOffset;
                const startPoint = img1Bottom - window.innerHeight;
                const endPointImg1 = startPoint + img1DisappearLength;
                const startPointImg2 = endPointImg1;
                const endPointImg2 = startPointImg2 + img2AppearLength;
                const pinEnd = endPointImg2 + pinExtra;
                gsap.to(img1, {
                    scale: 0.4,
                    display: 'none',
                    pointerEvents: 'none',
                    ease: 'none',
                    scrollTrigger: {
                        trigger: mapSection,
                        start: startPoint,
                        end: endPointImg1,
                        scrub: true,
                    }
                });

                gsap.fromTo(img2,
                    { opacity: 1, display: 'none', pointerEvents: 'none' },
                    {
                        top: 0,
                        left: 0,
                        width: '90%',
                        display: 'block',
                        opacity: 1,
                        pointerEvents: 'auto',
                        ease: 'none',
                        scrollTrigger: {
                            trigger: mapSection,
                            start: startPointImg2,
                            end: endPointImg2,
                            scrub: true,
                            onEnter: () => {
                                mapSection.classList.add('map--active');
                            },
                            onLeaveBack: () => {
                                mapSection.classList.remove('map--active');
                            }
                        }
                    }
                );

                ScrollTrigger.create({
                    trigger: mapSection,
                    start: startPoint,
                    end: pinEnd,
                    pin: true,
                    pinSpacing: true,
                    anticipatePin: 1,
                });
            },
        });
    }
    window.addEventListener('load', () => {
        if (mapSection) {
            animateMap();
        }
    });
    window.addEventListener('resize', () => {
        ScrollTrigger.refresh();
    });
}
